import{_ as t,o as e,c as s,O as n}from"./chunks/framework.92cbe775.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/onboarding-checklist.md","filePath":"en/product/onboarding-checklist.md","lastUpdated":1776135989000}'),r={name:"en/product/onboarding-checklist.md"};function i(l,a,d,o,c,p){return e(),s("div",null,a[0]||(a[0]=[n('<div class="brand-page-shell brand-page-shell--onboarding-checklist"><section class="brand-hero"><div><p class="brand-kicker">Onboarding Checklist</p><h1>Onboarding Checklist</h1><div class="brand-hero__panel"><span class="brand-pill">Before Delivery</span><strong>What slows onboarding down is often not missing features. It is incomplete scripts, documentation, samples, dependencies, and boundary information.</strong><p>This page lists the information that should be prepared before onboarding so customers, presales, and delivery can align faster.</p></div><p class="brand-lead"> Before a real scenario moves into onboarding, it is better to make the <strong>script folder, README, sample files, runtime dependencies, result shape, and risk boundary</strong> clear first. That makes later customer delivery, file processing, and CLI / local-bridge discussions much smoother. </p><div class="brand-chip-list"><span class="brand-chip">script folder</span><span class="brand-chip">README</span><span class="brand-chip">sample files</span><span class="brand-chip">risk boundary</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">Bring the checklist into the discussion</a><a class="cta-button" href="./customer-flow.html">View customer flow / delivery</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // ONBOARDING CHECKLIST</span><span>DOC 11</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">requiredPack</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;script_folder&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;readme&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;sample_file&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;runtime_dep&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">boundaryInfo</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;ai_allowed&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;manual_confirm&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;result_format&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">onboardingGoal</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;delivery_ready_handoff&#39;</span></span></div><div class="matrix-panel__callout">BETTER INPUTS MAKE ONBOARDING FASTER</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">prep</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">required</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scope</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">handoff_ready</span></span></div></div></div></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">01</p><h2>Script folder</h2><p>You need at least the executable main entry and the minimum folder structure that lets the platform understand what the capability is for.</p></article><article class="brand-card"><p class="brand-kicker">02</p><h2>README explanation</h2><p>Tell the platform what the script does, what it takes in, what it returns, and what prerequisites it needs.</p></article><article class="brand-card"><p class="brand-kicker">03</p><h2>Sample files</h2><p>If the script depends on input files or generates output files, it is better to provide example input and example output.</p></article><article class="brand-card"><p class="brand-kicker">04</p><h2>Risk boundary</h2><p>It is best to say early whether AI may call it, whether manual execution is allowed, and whether manual confirmation is required.</p></article></section><section class="brand-card"><p class="brand-kicker">Checklist Table</p><h2>These are the inputs you should ideally provide together at least once</h2><table><thead><tr><th>Preparation item</th><th>Should it be provided early</th><th>Why it matters</th><th>Recommended explanation</th></tr></thead><tbody><tr><td>Script folder</td><td>Required</td><td>There is no onboarding path without the actual execution content</td><td>At minimum, make the main entry and the minimum folder structure explicit.</td></tr><tr><td><code>README.md</code></td><td>Required</td><td>It helps review, naming, and later maintenance</td><td>It should explain purpose, input, output, prerequisites, and result form.</td></tr><tr><td>Sample input</td><td>Strongly recommended</td><td>It makes onboarding effects much faster to verify</td><td>If file processing is involved, provide example files.</td></tr><tr><td>Sample output</td><td>Strongly recommended</td><td>It helps confirm whether the result matches expectation</td><td>This can be a sample output file, screenshot, or result-field explanation.</td></tr><tr><td>Runtime dependencies</td><td>Strongly recommended</td><td>They affect deployment and onboarding method</td><td>For example Python version, third-party packages, system tools, or external services.</td></tr><tr><td>Whether AI may call it</td><td>Recommended</td><td>It decides whether the intelligent brain may recommend this capability</td><td>Not every script enters AI recommendation scope by default.</td></tr><tr><td>Whether manual execution is allowed</td><td>Recommended</td><td>It decides whether the page opens a manual entry</td><td>This can be controlled separately from AI invocation.</td></tr><tr><td>Whether manual confirmation is required</td><td>Recommended</td><td>It controls the confirmation step for higher-risk actions</td><td>This fits scenarios such as rewriting data, sending messages, or triggering external actions.</td></tr><tr><td>Result form</td><td>Recommended</td><td>It affects result display and the result-download entry</td><td>The result can be text, a table, Excel, a zip package, or another artifact.</td></tr><tr><td>Expected execution duration</td><td>Recommended</td><td>It affects frontend experience and result-return method</td><td>Short tasks and long tasks usually need different user experience design.</td></tr><tr><td>Data-security boundary</td><td>Recommended</td><td>It affects whether the path should run in cloud execution or local bridging</td><td>When intranet or private resources are involved, the CLI / Agent route is usually needed.</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">If Not Ready Yet</p><h2>If the materials are not complete yet, start with these first</h2><ul class="brand-list"><li>You can start with the public experience entry to feel the platform path first</li><li>You can begin a discussion with only a minimal script folder and a README</li><li>If you are still deciding where the platform fits, start from the product overview and FAQ</li><li>If the task clearly depends on files, adding sample files and expected results early will save time</li></ul></article><article class="brand-card"><p class="brand-kicker">What This Avoids</p><h2>Why this checklist is worth reading early</h2><ul class="brand-list"><li>It avoids the vague &quot;I have a script&quot; discussion where nobody can say how it should connect</li><li>It avoids discovering the result shape too late and having to rework the result page or file-download path</li><li>It avoids adding safety boundaries late because risky actions were not declared up front</li><li>It avoids treating a scenario as a pure web capability when it should really go through local bridging</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Path Matching</p><h2>According to your current state, which page should you read next</h2><table><thead><tr><th>Current state</th><th>Best next page</th><th>Why</th><th>Notes</th></tr></thead><tbody><tr><td>You are only learning the platform for the first time</td><td><a href="../guide/getting-started.html">Getting Started</a></td><td>Start by judging the platform position and the real entry points</td><td>You do not need a full delivery checklist on day one.</td></tr><tr><td>You are already preparing for a customer or a real project</td><td><a href="./customer-flow.html">Customer Flow / Delivery</a></td><td>Understand the formal delivery path and hot-update flow first</td><td>This fits joint review by presales, delivery, and the customer.</td></tr><tr><td>The task depends on input files and result files</td><td><a href="./file-results.html">File Upload &amp; Result Delivery</a></td><td>Clarify the file chain first</td><td>This is especially useful for reporting, export, and batch data-processing scenarios.</td></tr><tr><td>The script depends on a local environment or intranet resources</td><td><a href="./cli.html">CLI Guide</a></td><td>Local bridging is more likely to be needed</td><td>These scenarios are usually not solved only through a browser page.</td></tr></tbody></table></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>Read the checklist, delivery flow, and file path together</h2><p class="brand-lead">Once a real onboarding stage begins, the more effective move is usually not to stay in abstract vision. It is to align delivery flow, the file path, and the local-bridge boundary together once.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./customer-flow.html"><span>Flow</span><strong>Customer Flow / Delivery</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>File Upload &amp; Result Delivery</strong></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>Deliverables / Doc Entry</strong></a><a class="brand-link-card" href="./cli.html"><span>CLI</span><strong>CLI Guide</strong></a></div></div></section></div>',1)]))}const u=t(r,[["render",i]]);export{m as __pageData,u as default};
